/// <summary>
/// Utility methods that exercise the runtime metadata (reflection) API: DictTable, DictField,
/// DictEnum and DictClass.
/// </summary>
public class ConDemoReflectionUtil
{
}

Method.Source:
/// <summary>
/// Writes every non-system field of the supplied record to the infolog, using the field label
/// and the dynamically read field value.
/// </summary>
/// <param name = "_record">The record buffer to dump.</param>
public static void dumpRecord(Common _record)
{
    DictTable dictTable = new DictTable(_record.TableId);
    int       i;

    for (i = 1; i <= dictTable.fieldCnt(); i++)
    {
        FieldId   fieldId   = dictTable.fieldCnt2Id(i);
        DictField dictField = dictTable.fieldObject(fieldId);

        if (!dictField || dictField.isSystem())
        {
            continue;
        }

        info(strFmt('%1: %2', dictField.label(), _record.(fieldId)));
    }
}

/// <summary>
/// Resolves the label of an enum value whose enum type is only known at runtime.
/// </summary>
/// <param name = "_enumId">The id of the enum.</param>
/// <param name = "_value">The enum value.</param>
/// <returns>The label of the enum value.</returns>
public static str enumLabel(EnumId _enumId, int _value)
{
    DictEnum dictEnum = new DictEnum(_enumId);

    return dictEnum.value2Label(_value);
}

/// <summary>
/// Calls a static method on the supplied class, but only when that method actually exists.
/// </summary>
/// <param name = "_classId">The id of the class to call.</param>
/// <param name = "_methodName">The name of the static method to call.</param>
public static void runIfPresent(ClassId _classId, str _methodName)
{
    SysDictClass dictClass = new SysDictClass(_classId);

    if (dictClass.hasStaticMethod(_methodName))
    {
        dictClass.callStatic(_methodName);
    }
}
